void MessageArea::do_load_more_message()
{
    if(isLoading){
        return;
    }
    isLoading = true;

    QString timestamp =UserManager::GetInstance()->GetHistoryTimestamp(UserManager::GetInstance()->GetPeerUid()).toString("yyyy-MM-dd HH:mm:ss");
